function renderProfile(){const e=document.getElementById("profile-photo");data.profile.photoUrl?e.innerHTML=`<img src="${data.profile.photoUrl}" alt="${data.profile.name}">`:e.textContent=data.profile.name.split(" ").map(e=>e[0]).join(""),document.getElementById("profile-name").textContent=data.profile.name,document.getElementById("profile-role").textContent=data.profile.role,document.getElementById("profile-affiliation").textContent=data.profile.affiliation||"";const t=document.getElementById("profile-address");t&&(t.innerHTML=(data.profile.address||[]).map((e,t)=>0===t?`<span><i class="fa-solid fa-location-dot" aria-hidden="true"></i> ${e}</span>`:`<span>${e}</span>`).join("<br>"));const n=document.getElementById("profile-social");n&&(n.innerHTML=(data.profile.social||[]).map(e=>`<a class="social-link" href="${e.url}" target="_blank" rel="noopener noreferrer"><i class="${e.icon}" aria-hidden="true"></i><span>${e.label}</span></a>`).join(""))}function renderBio(){const e=document.getElementById("about-bio-text");e&&(e.textContent=data.profile.about);const t=document.getElementById("about-points");t&&(t.innerHTML=(data.profile.signaturePoints||[]).map(e=>`<p class="about-point">${e}</p>`).join(""))}function renderLatestPostsPreview(){const e=document.getElementById("posts-preview-body");if(!e)return;const t=(data.blogs||[]).slice(0,3);if(!t.length){const e=document.getElementById("posts-preview");return void(e&&(e.hidden=!0))}e.innerHTML=t.map(e=>`\n        <tr>\n          <td class="news-date">${e.date}</td>\n          <td class="news-item">\n            <a href="blog.html">${e.title}</a><span class="post-platform"> · ${e.platform}</span>\n          </td>\n        </tr>`).join("")}initPage("About"),renderProfile(),renderBio(),renderLatestPostsPreview(),setupReveal();